// 文件：src/models/Todo.js（数据模型）
class Todo {
  constructor(db) {
    this.db = db;
  }

  // 创建待办事项
  create(title, description = '') {
    const stmt = this.db.prepare(`
      INSERT INTO todos (title, description, completed, created_at)
      VALUES (?, ?, 0, datetime('now'))
    `);
    const result = stmt.run(title, description);
    return this.getById(result.lastInsertRowid);
  }

  // 根据ID获取待办事项
  getById(id) {
    const stmt = this.db.prepare('SELECT * FROM todos WHERE id = ?');
    return stmt.get(id);
  }

  // 获取所有待办事项
  getAll() {
    const stmt = this.db.prepare('SELECT * FROM todos ORDER BY created_at DESC');
    return stmt.all();
  }

  // 更新待办事项
  update(id, updates) {
    const allowedFields = ['title', 'description', 'completed'];
    const fields = [];
    const values = [];

    for (const [key, value] of Object.entries(updates)) {
      if (allowedFields.includes(key)) {
        fields.push(`${key} = ?`);
        values.push(value);
      }
    }

    if (fields.length === 0) return null;

    values.push(id);
    const stmt = this.db.prepare(`
      UPDATE todos SET ${fields.join(', ')} WHERE id = ?
    `);
    stmt.run(...values);
    return this.getById(id);
  }

  // 删除待办事项
  delete(id) {
    const stmt = this.db.prepare('DELETE FROM todos WHERE id = ?');
    const result = stmt.run(id);
    return result.changes > 0;
  }

  // 切换完成状态
  toggleComplete(id) {
    const todo = this.getById(id);
    if (!todo) return null;
    return this.update(id, { completed: !todo.completed });
  }
}

module.exports = Todo;

