// 文件：src/models/Todo.js（数据模型）
class Todo {
  constructor(db) {
    this.db = db;
  }

  // 创建待办事项
  create(title, description = '') {
    const stmt = this.db.prepare(`
      INSERT INTO todos (title, description, completed, created_at)
      VALUES (?, ?, 0, datetime('now'))
    `);
    const result = stmt.run(title, description);
    return this.getById(result.lastInsertRowid);
  }

  // 根据ID获取待办事项
  getById(id) {
    const stmt = this.db.prepare('SELECT * FROM todos WHERE id = ?');
    return stmt.get(id);
  }

  // 获取所有待办事项
  getAll() {
    const stmt = this.db.prepare('SELECT * FROM todos ORDER BY created_at DESC');
    return stmt.all();
  }

  // 更新待办事项
  update(id, updates) {
    const allowedFields = ['title', 'description', 'completed'];
    const fields = [];
    const values = [];

    for (const [key, value] of Object.entries(updates)) {
      if (allowedFields.includes(key)) {
        fields.push(`${key} = ?`);
        values.push(value);
      }
    }

    if (fields.length === 0) return null;

    values.push(id);
    const stmt = this.db.prepare(`
      UPDATE todos SET ${fields.join(', ')} WHERE id = ?
    `);
    stmt.run(...values);
    return this.getById(id);
  }

  // 删除待办事项
  delete(id) {
    const stmt = this.db.prepare('DELETE FROM todos WHERE id = ?');
    const result = stmt.run(id);
    return result.changes > 0;
  }

  // 切换完成状态
  toggleComplete(id) {
    const todo = this.getById(id);
    if (!todo) return null;
    return this.update(id, { completed: !todo.completed });
  }
}

module.exports = Todo;

// 文件：src/routes/todoRoutes.js（路由处理）
const express = require('express');
const Todo = require('../models/Todo');
const { getDb } = require('../db/database');

const router = express.Router();
const todoModel = new Todo(getDb());

// GET /api/todos - 获取所有待办事项
router.get('/', (req, res) => {
  try {
    const todos = todoModel.getAll();
    res.json({ success: true, data: todos });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

// POST /api/todos - 创建新待办事项
router.post('/', (req, res) => {
  try {
    const { title, description } = req.body;
    if (!title || title.trim() === '') {
      return res.status(400).json({
        success: false,
        error: '标题不能为空'
      });
    }
    const todo = todoModel.create(title.trim(), description || '');
    res.status(201).json({ success: true, data: todo });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

// PUT /api/todos/:id - 更新待办事项
router.put('/:id', (req, res) => {
  try {
    const { id } = req.params;
    const { title, description, completed } = req.body;
    const updates = {};
    if (title !== undefined) updates.title = title;
    if (description !== undefined) updates.description = description;
    if (completed !== undefined) updates.completed = completed;

    const todo = todoModel.update(parseInt(id), updates);
    if (!todo) {
      return res.status(404).json({ success: false, error: '待办事项不存在' });
    }
    res.json({ success: true, data: todo });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

// DELETE /api/todos/:id - 删除待办事项
router.delete('/:id', (req, res) => {
  try {
    const { id } = req.params;
    const deleted = todoModel.delete(parseInt(id));
    if (!deleted) {
      return res.status(404).json({ success: false, error: '待办事项不存在' });
    }
    res.json({ success: true, message: '删除成功' });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

// PATCH /api/todos/:id/toggle - 切换完成状态
router.patch('/:id/toggle', (req, res) => {
  try {
    const { id } = req.params;
    const todo = todoModel.toggleComplete(parseInt(id));
    if (!todo) {
      return res.status(404).json({ success: false, error: '待办事项不存在' });
    }
    res.json({ success: true, data: todo });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

module.exports = router;

