# 示例：性能瓶颈诊断与优化
import time
from typing import List, Dict
from functools import lru_cache

class InefficientDataProcessor:
    """低效的数据处理类 - 存在多个性能问题"""

    def __init__(self, data: List[Dict]):
        self.data = data

    def find_by_field(self, field: str, value) -> List[Dict]:
        """
        问题：每次调用都遍历全部数据 O(n)
        """
        results = []
        for item in self.data:
            if item.get(field) == value:
                results.append(item)
        return results

    def count_by_field(self, field: str, value) -> int:
        """
        问题：重复遍历相同数据，O(n) * 调用次数
        """
        count = 0
        for item in self.data:
            if item.get(field) == value:
                count += 1
        return count

    def get_statistics(self) -> Dict:
        """
        问题：多次重复遍历数据
        """
        unique_values = set()
        total_count = 0
        field_values = []

        # 第一次遍历：收集所有字段值
        for item in self.data:
            for key, value in item.items():
                if key == 'category':
                    unique_values.add(value)
                    field_values.append(value)
            total_count += 1

        # 第二次遍历：计算分类统计
        category_count = {}
        for item in self.data:
            cat = item.get('category')
            category_count[cat] = category_count.get(cat, 0) + 1

        # 第三次遍历：找最大值
        max_value = None
        for item in self.data:
            val = item.get('value', 0)
            if max_value is None or val > max_value:
                max_value = val

        return {
            'total': total_count,
            'unique_categories': len(unique_values),
            'category_distribution': category_count,
            'max_value': max_value
        }

# 优化后的版本
class OptimizedDataProcessor:
    """优化后的数据处理类"""

    def __init__(self, data: List[Dict]):
        self.data = data
        # 建立索引以加速查询
        self._indexes = {}
        self._build_indexes()

    def _build_indexes(self):
        """预先建立索引，O(n)一次性建立，后续查询O(1)"""
        for item in self.data:
            for key, value in item.items():
                if key not in self._indexes:
                    self._indexes[key] = {}

                if value not in self._indexes[key]:
                    self._indexes[key][value] = []

                self._indexes[key][value].append(item)

    def find_by_field(self, field: str, value) -> List[Dict]:
        """使用索引快速查找 O(1)"""
        if field not in self._indexes:
            return []
        return self._indexes[field].get(value, [])

    def count_by_field(self, field: str, value) -> int:
        """使用索引快速计数 O(1)"""
        if field not in self._indexes:
            return 0
        return len(self._indexes[field].get(value, []))

    def get_statistics(self) -> Dict:
        """只遍历一次，计算所有统计信息"""
        category_count = {}
        max_value = None
        total = len(self.data)

        for item in self.data:
            # 统计分类
            cat = item.get('category')
            category_count[cat] = category_count.get(cat, 0) + 1

            # 找最大值
            val = item.get('value', 0)
            if max_value is None or val > max_value:
                max_value = val

        return {
            'total': total,
            'unique_categories': len(category_count),
            'category_distribution': category_count,
            'max_value': max_value
        }

    @lru_cache(maxsize=128)
    def cached_find(self, field: str, value):
        """缓存频繁查询的结果"""
        return self.find_by_field(field, value)

# 性能对比测试
def benchmark():
    # 生成测试数据
    test_data = [
        {'id': i, 'category': f'cat_{i % 10}', 'value': i * 1.5, 'name': f'item_{i}'}
        for i in range(10000)
    ]

    # 测试原始版本
    inefficient = InefficientDataProcessor(test_data)

    start = time.time()
    for _ in range(100):
        inefficient.find_by_field('category', 'cat_5')
        inefficient.count_by_field('category', 'cat_5')
    inefficient_time = time.time() - start

    # 测试优化版本
    optimized = OptimizedDataProcessor(test_data)

    start = time.time()
    for _ in range(100):
        optimized.find_by_field('category', 'cat_5')
        optimized.count_by_field('category', 'cat_5')
    optimized_time = time.time() - start

    print(f"原始版本耗时: {inefficient_time:.4f}秒")
    print(f"优化版本耗时: {optimized_time:.4f}秒")
    print(f"性能提升: {inefficient_time / optimized_time:.2f}x")

if __name__ == "__main__":
    benchmark()
    # 输出示例:
    # 原始版本耗时: 2.3456秒
    # 优化版本耗时: 0.0234秒
    # 性能提升: 100.24x

