// 示例1：智能补全场景 - 用户认证模块
// 文件：auth/middleware.js

const jwt = require('jsonwebtoken');
const User = require('../models/User');
const { ApiError } = require('../utils/errors');


/**
 * 认证中间件 - 验证JWT令牌
 * @param {Object} req - 请求对象
 * @param {Object} res - 响应对象
 * @param {Function} next - 下一个中间件
 */
async function authMiddleware(req, res, next) {
  try {
    // 获取请求头中的令牌
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      throw new ApiError('UNAUTHORIZED', '未提供认证令牌');
    }

    const token = authHeader.substring(7);

    // 验证令牌
    const decoded = jwt.verify(token, process.env.JWT_SECRET);

    // 获取用户信息
    const user = await User.findById(decoded.userId);
    if (!user) {
      throw new ApiError('UNAUTHORIZED', '用户不存在');
    }

    if (!user.isActive) {
      throw new ApiError('FORBIDDEN', '账户已被禁用');
    }

    // 将用户信息挂载到请求对象
    req.user = user;
    req.userId = user.id;

    next();
  } catch (error) {
    if (error.name === 'JsonWebTokenError') {
      next(new ApiError('UNAUTHORIZED', '令牌无效'));
    } else if (error.name === 'TokenExpiredError') {
      next(new ApiError('UNAUTHORIZED', '令牌已过期'));
    } else {
      next(error);
    }
  }
}

module.exports = authMiddleware;

