from django.db import models
from django.contrib.auth.models import AbstractBaseUser, BaseUserManager, PermissionsMixin
from django.utils import timezone

class UserManager(BaseUserManager):
    """自定义用户管理器"""

    def create_user(self, email, username, password=None, **extra_fields):
        """创建普通用户"""
        if not email:
            raise ValueError('用户必须提供邮箱地址')
        if not username:
            raise ValueError('用户必须提供用户名')

        email = self.normalize_email(email)
        user = self.model(email=email, username=username, **extra_fields)
        user.set_password(password)
        user.save(using=self._db)
        return user

    def create_superuser(self, email, username, password=None, **extra_fields):
        """创建超级用户"""
        extra_fields.setdefault('is_staff', True)
        extra_fields.setdefault('is_superuser', True)
        extra_fields.setdefault('is_active', True)

        if extra_fields.get('is_staff') is not True:
            raise ValueError('超级用户必须设置 is_staff=True')
        if extra_fields.get('is_superuser') is not True:
            raise ValueError('超级用户必须设置 is_superuser=True')

        return self.create_user(email, username, password, **extra_fields)

class User(AbstractBaseUser, PermissionsMixin):
    """自定义用户模型"""
    email = models.EmailField('邮箱', unique=True)
    username = models.CharField('用户名', max_length=150, unique=True)
    first_name = models.CharField('名', max_length=150, blank=True)
    last_name = models.CharField('姓', max_length=150, blank=True)
    is_active = models.BooleanField('激活状态', default=True)
    is_staff = models.BooleanField('员工状态', default=False)
    date_joined = models.DateTimeField('注册时间', default=timezone.now)

    # 用户档案信息
    bio = models.TextField('个人简介', blank=True)
    avatar_url = models.URLField('头像URL', blank=True)
    phone = models.CharField('手机号', max_length=20, blank=True)

    # 关系定义
    orders = models.ForeignKey('orders.Order', on_delete=models.SET_NULL, null=True, related_name='user_orders')

    objects = UserManager()

    USERNAME_FIELD = 'email'  // 使用邮箱作为登录标识
    REQUIRED_FIELDS = ['username']

    class Meta:
        db_table = 'users'
        verbose_name = '用户'
        verbose_name_plural = '用户列表'

    def __str__(self):
        return self.email

    def get_full_name(self):
        return f'{self.first_name} {self.last_name}'.strip()

    def get_short_name(self):
        return self.first_name or self.username
```

