# Python Flask 项目示例 - 用户认证流程的调用链分析

# src/__init__.py
"""应用初始化模块"""
from flask import Flask
from .config import Config
from .extensions import db, login_manager

def create_app(config_class=Config):
    """应用工厂函数"""
    app = Flask(__name__)
    app.config.from_object(config_class)

    # 初始化扩展
    db.init_app(app)
    login_manager.init_app(app)

    # 注册蓝图
    from .routes import auth, users, orders
    app.register_blueprint(auth.bp)
    app.register_blueprint(users.bp)
    app.register_blueprint(orders.bp)

    return app

# src/routes/auth.py
"""认证路由模块"""
from flask import Blueprint, request, jsonify
from .services.auth_service import AuthService

bp = Blueprint('auth', __name__, url_prefix='/api/auth')
auth_service = AuthService()

@bp.route('/login', methods=['POST'])
def login():
    """用户登录接口 - 认证流程入口"""
    data = request.get_json()
    token = auth_service.authenticate(
        username=data.get('username'),
        password=data.get('password')
    )
    return jsonify({'token': token})

@bp.route('/register', methods=['POST'])
def register():
    """用户注册接口"""
    data = request.get_json()
    user = auth_service.create_user(
        username=data.get('username'),
        email=data.get('email'),
        password=data.get('password')
    )
    return jsonify({'user_id': user.id}), 201

# src/routes/services/auth_service.py
"""认证服务层 - 处理核心业务逻辑"""
from ..models.user import User
from ..middleware.validator import validate_email, hash_password
from ..utils.jwt_helper import generate_token
from ..utils.rate_limiter import check_rate_limit

class AuthService:
    """认证服务类"""

    def authenticate(self, username, password):
        """
        认证流程：
        1. 检查请求频率限制
        2. 查找用户
        3. 验证密码
        4. 生成JWT令牌
        """
        # 步骤1：频率限制检查
        if not check_rate_limit(username, limit=5, window=300):
            raise ValueError("请求过于频繁，请稍后再试")

        # 步骤2：查找用户
        user = User.query.filter_by(username=username).first()
        if not user:
            raise ValueError("用户名或密码错误")

        # 步骤3：验证密码
        if not self._verify_password(password, user.password_hash):
            raise ValueError("用户名或密码错误")

        # 步骤4：生成令牌
        token = generate_token(user_id=user.id, role=user.role)
        return token

    def _verify_password(self, password, password_hash):
        """验证密码"""
        import hashlib
        return hashlib.sha256(password.encode()).hexdigest() == password_hash

    def create_user(self, username, email, password):
        """创建新用户"""
        # 验证邮箱格式
        if not validate_email(email):
            raise ValueError("无效的邮箱格式")

        # 密码加密
        password_hash = hash_password(password)

        # 创建用户记录
        user = User(
            username=username,
            email=email,
            password_hash=password_hash
        )
        db.session.add(user)
        db.session.commit()
        return user

# src/models/user.py
"""用户数据模型"""
from . import db
from datetime import datetime

class User(db.Model):
    """用户模型"""
    __tablename__ = 'users'

    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(256), nullable=False)
    role = db.Column(db.String(20), default='user')
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

    # 关系定义
    orders = db.relationship('Order', backref='user', lazy=True)

    def __repr__(self):
        return f'<User {self.username}>'

# src/utils/jwt_helper.py
"""JWT令牌生成工具"""
import jwt
from datetime import datetime, timedelta
from flask import current_app

def generate_token(user_id, role, expires_in=3600):
    """生成JWT令牌"""
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': datetime.utcnow() + timedelta(seconds=expires_in),
        'iat': datetime.utcnow()
    }
    return jwt.encode(
        payload,
        current_app.config['SECRET_KEY'],
        algorithm='HS256'
    )

# Windsurf AI 调用链分析结果示例
// 登录请求的完整调用链：
