// 电商系统订单处理流程的数据流向分析

// 1. 订单创建入口
// src/features/orders/api/orderController.ts

import { Request, Response } from 'express';
import { OrderService } from '../services/orderService';
import { InventoryService } from '../../inventory/services/inventoryService';
import { PaymentService } from '../../payment/services/paymentService';
import { NotificationService } from '../../notification/services/notificationService';

const orderService = new OrderService();
const inventoryService = new InventoryService();
const paymentService = new PaymentService();
const notificationService = new NotificationService();

export class OrderController {
    /**
     * 创建订单 - 核心业务流程入口
     * 数据流向：请求验证 → 库存检查 → 支付处理 → 订单保存 → 通知发送
     */
    async createOrder(req: Request, res: Response) {
        try {
            const { userId, items, paymentMethod } = req.body;

            // 步骤1：验证请求数据
            const validatedData = orderService.validateOrderRequest(req.body);

            // 步骤2：检查并锁定库存
            const inventoryResult = await inventoryService.reserveItems(items);
            if (!inventoryResult.success) {
                return res.status(400).json({ error: '库存不足' });
            }

            // 步骤3：处理支付
            const paymentResult = await paymentService.processPayment({
                userId,
                amount: validatedData.totalAmount,
                method: paymentMethod
            });

            if (!paymentResult.success) {
                // 支付失败，释放库存
                await inventoryService.releaseItems(inventoryResult.reservationId);
                return res.status(402).json({ error: '支付失败' });
            }

            // 步骤4：创建订单记录
            const order = await orderService.createOrder({
                userId,
                items: validatedData.items,
                totalAmount: validatedData.totalAmount,
                paymentId: paymentResult.paymentId,
                status: 'confirmed'
            });

            // 步骤5：发送通知
            await notificationService.sendOrderConfirmation(order);

            return res.status(201).json({
                success: true,
                orderId: order.id,
                orderNumber: order.orderNumber
            });

        } catch (error) {
            console.error('订单创建失败:', error);
            return res.status(500).json({ error: '服务器内部错误' });
        }
    }
}

// 2. 订单服务 - 业务逻辑处理中心
// src/features/orders/services/orderService.ts

import { OrderRepository } from '../repositories/orderRepository';
import { Order } from '../models/order';
import { generateOrderNumber } from '../utils/orderNumberGenerator';

export class OrderService {
    private orderRepository: OrderRepository;

    constructor() {
        this.orderRepository = new OrderRepository();
    }

    /**
     * 验证订单请求数据
     * 数据转换：从API请求格式转换为业务模型格式
     */
    validateOrderRequest(data: any) {
        // 输入验证
        if (!data.userId || !data.items || data.items.length === 0) {
            throw new Error('缺少必要的订单信息');
        }

        // 计算订单总金额
        const totalAmount = data.items.reduce((sum: number, item: any) => {
            return sum + (item.price * item.quantity);
        }, 0);

        // 转换和标准化数据
        return {
            userId: data.userId,
            items: data.items.map((item: any) => ({
                productId: item.productId,
                quantity: item.quantity,
                unitPrice: item.price,
                subtotal: item.price * item.quantity
            })),
            totalAmount: Math.round(totalAmount * 100) / 100,  // 保留两位小数
            currency: 'CNY',
            createdAt: new Date()
        };
    }

    /**
     * 创建订单
     * 数据持久化：保存到数据库
     */
    async createOrder(orderData: any): Promise<Order> {
        // 生成订单号
        const orderNumber = await generateOrderNumber();

        // 构建订单实体
        const order = new Order({
            orderNumber,
            userId: orderData.userId,
            items: orderData.items,
            totalAmount: orderData.totalAmount,
            paymentId: orderData.paymentId,
            status: orderData.status,
            createdAt: new Date()
        });

        // 保存到数据库
        return await this.orderRepository.save(order);
    }
}

