// │       └── productsSlice.ts
// └── store/

// 产品列表组件 - 展示完整的依赖关系
// src/features/products/ProductList.tsx

import React, { useEffect, useState } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { fetchProducts, selectAllProducts } from './productsSlice';
import { ProductCard } from '../../components/common/ProductCard';
import { Spinner } from '../../components/common/Spinner';
import { ErrorMessage } from '../../components/common/ErrorMessage';
import { Pagination } from '../../components/common/Pagination';

// 类型定义
interface ProductListProps {
  categoryId?: string;
  onProductClick?: (productId: string) => void;
}

interface RootState {
  products: {
    items: Product[];
    loading: boolean;
    error: string | null;
    pagination: {
      page: number;
      pageSize: number;
      total: number;
    };
  };
}

// 产品数据模型
interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  category: {
    id: string;
    name: string;
  };
  images: string[];
  stock: number;
}

/**
 * ProductList 组件
 * 
 * 功能说明：
 * - 显示产品列表，支持分类筛选
 * - 集成 Redux 状态管理
 * - 支持分页加载
 * - 子组件通信通过回调函数
 * 
 * 数据流向：
 * Redux Store → Component Props → Child Components
 * 
 * 依赖关系：
 * - productsSlice (状态管理)
 * - ProductCard (展示组件)
 * - Spinner/ErrorMessage/Pagination (通用组件)
 */
export const ProductList: React.FC<ProductListProps> = ({ 
  categoryId, 
  onProductClick 
}) => {
  const dispatch = useDispatch();
  const { items, loading, error, pagination } = useSelector(selectAllProducts);
  const [currentPage, setCurrentPage] = useState(1);

  // 副作用：组件挂载时获取产品列表
  useEffect(() => {
    dispatch(fetchProducts({ 
      page: currentPage, 
      pageSize: 20,
      categoryId 
    }) as any);
  }, [dispatch, currentPage, categoryId]);

  // 加载状态
  if (loading) {
    return <Spinner message="加载产品中..." />;
  }

  // 错误状态
  if (error) {
    return <ErrorMessage message={error} onRetry={() => {
      dispatch(fetchProducts({ page: currentPage, categoryId }) as any);
    }} />;
  }

  // 空状态
  if (items.length === 0) {
    return (
      <div className="product-list-empty">
        <p>暂无产品</p>
      </div>
    );
  }

  // 产品卡片点击处理
  const handleProductClick = (product: Product) => {
    onProductClick?.(product.id);
  };

  return (
    <div className="product-list">
      <div className="product-grid">
        {items.map(product => (
          <ProductCard 
            key={product.id}
            product={product}
            onClick={() => handleProductClick(product)}
          />
        ))}
      </div>

      <Pagination
        currentPage={pagination.page}
        totalPages={Math.ceil(pagination.total / pagination.pageSize)}
        onPageChange={setCurrentPage}
      />
    </div>
  );
};

export default ProductList;
```



## 常见错误

- 忽略项目结构约定，直接把所有文件放在同一目录，导致AI难以理解模块划分
- 循环依赖：模块A依赖B，B依赖C，C又依赖A，AI难以追踪完整的调用链
- 命名不规范：使用模糊的变量名如 data、temp、tmp，增加AI理解的难度
- 缺少类型注解：在TypeScript/JavaScript项目中不使用类型，导致类型推断不准确
- 忽视文档注释：不写关键的类和函数文档，降低AI对业务逻辑的理解
- 过度嵌套的回调或Promise链：导致调用链追踪困难，建议使用async/await
- 硬编码配置值：把应该配置化的值硬编码在代码中，增加上下文理解的复杂度
- 魔法数字和字符串：使用未定义的常量如 if (status === 1)，应使用有意义的常量
- 忽视测试文件：测试文件包含丰富的使用示例和期望行为，应作为重要的上下文来源


## 最佳实践

- 建立清晰、层次分明的项目结构，按功能模块划分代码，而非按文件类型
- 使用一致的命名规范和代码风格，便于AI和团队成员快速理解
- 充分利用TypeScript的类型系统和JSDoc注释，增强代码的可读性
- 在关键业务逻辑处添加注释，说明数据流向和状态变化
- 使用依赖注入和工厂模式，使模块间的依赖关系更明确
- 保持函数和类的单一职责原则，每个模块专注于特定功能
- 定期使用Windsurf分析项目架构，确保结构清晰合理
- 编写和更新README文档，包含项目结构说明和关键模块介绍
- 在重构前先使用Windsurf理解相关代码的上下文，避免破坏现有功能
- 为API接口添加Swagger/OpenAPI文档，帮助AI理解前后端交互约定

