class CRUDFactory {
  constructor(entityName) {
    this.entityName = entityName;
    this.capitalizedName = this.capitalize(entityName);
  }

  // 首字母大写
  capitalize(str) {
    return str.charAt(0).toUpperCase() + str.slice(1);
  }

  // 生成 Model 文件
  generateModel() {
    return `// auto-generated model for ${this.entityName}
import { Model, DataTypes } from 'sequelize';

export default class ${this.capitalizedName}Model extends Model {
  static init(sequelize) {
    return super.init({
      id: { type: DataTypes.INTEGER, primaryKey: true, autoIncrement: true },
      // 在此添加 ${this.entityName} 的字段定义
    }, {
      sequelize,
      tableName: '${this.entityName}s',
      timestamps: true,
    });
  }
}
`;
  }

  // 生成 Service 文件
  generateService() {
    return `// auto-generated service for ${this.entityName}
import ${this.capitalizedName}Model from '../models/${this.entityName}';

export class ${this.capitalizedName}Service {
  // 创建
  async create(data) {
    return await ${this.capitalizedName}Model.create(data);
  }

  // 查询单条
  async findById(id) {
    return await ${this.capitalizedName}Model.findByPk(id);
  }

  // 查询列表
  async findAll(options = {}) {
    return await ${this.capitalizedName}Model.findAll(options);
  }

  // 更新
  async update(id, data) {
    const instance = await this.findById(id);
    if (instance) {
      return await instance.update(data);
    }
    return null;
  }

  // 删除
  async delete(id) {
    const instance = await this.findById(id);
    if (instance) {
      await instance.destroy();
      return true;
    }
    return false;
  }
}

export default new ${this.capitalizedName}Service();
`;
  }

  // 生成 Controller 文件
  generateController() {
    return `// auto-generated controller for ${this.entityName}
import ${this.capitalizedName}Service from '../services/${this.entityName}';

export const ${this.entityName}Controller = {
  // 创建
  async create(req, res) {
    try {
      const result = await ${this.capitalizedName}Service.create(req.body);
      res.status(201).json({ success: true, data: result });
    } catch (error) {
      res.status(500).json({ success: false, error: error.message });
    }
  },

  // 获取详情
  async getById(req, res) {
    try {
      const result = await ${this.capitalizedName}Service.findById(req.params.id);
      if (result) {
        res.json({ success: true, data: result });
      } else {
        res.status(404).json({ success: false, error: 'Not found' });
      }
    } catch (error) {
      res.status(500).json({ success: false, error: error.message });
    }
  },

  // 获取列表
  async list(req, res) {
    try {
      const result = await ${this.capitalizedName}Service.findAll(req.query);
      res.json({ success: true, data: result });
    } catch (error) {
      res.status(500).json({ success: false, error: error.message });
    }
  },

  // 更新
  async update(req, res) {
    try {
      const result = await ${this.capitalizedName}Service.update(req.params.id, req.body);
      res.json({ success: true, data: result });
    } catch (error) {
      res.status(500).json({ success: false, error: error.message });
    }
  },

  // 删除
  async delete(req, res) {
    try {
      const success = await ${this.capitalizedName}Service.delete(req.params.id);
      res.json({ success });
    } catch (error) {
      res.status(500).json({ success: false, error: error.message });
    }
  },
};
`;
  }

  // 生成全部文件
  generateAll() {
    return {
      model: this.generateModel(),
      service: this.generateService(),
      controller: this.generateController()
    };
  }
}

// 使用示例：为 'user' 实体生成 CRUD 代码
