// 示例3：批量文件替换和更新脚本
// 场景：将项目中的旧 API 路径批量替换为新路径

/**
 * Windsurf 批量替换脚本示例
 * 功能：批量替换多个文件中的指定内容
 */

const fs = require('fs');
const path = require('path');

class BatchReplacer {
  constructor() {
    this.stats = {
      scanned: 0,
      modified: 0,
      skipped: 0,
      errors: []
    };
  }

  // 扫描并替换文件
  async replaceInFiles(directory, replacements, options = {}) {
    const {
      extensions = ['.ts', '.tsx', '.js', '.jsx'],
      exclude = ['node_modules', '.git', 'dist'],
      preview = false  // 预览模式，不实际修改
    } = options;

    const files = this.getFiles(directory, extensions, exclude);

    for (const file of files) {
      try {
        this.stats.scanned++;
        await this.processFile(file, replacements, preview);
      } catch (error) {
        this.stats.errors.push({ file, error: error.message });
      }
    }

    return this.stats;
  }

  // 获取所有符合条件文件
  getFiles(dir, extensions, exclude) {
    const results = [];

    function walk(currentDir) {
      const items = fs.readdirSync(currentDir);

      for (const item of items) {
        const fullPath = path.join(currentDir, item);
        const stat = fs.statSync(fullPath);

        // 跳过排除的目录
        if (stat.isDirectory() && !exclude.includes(item)) {
          walk(fullPath);
        } else if (stat.isFile()) {
          const ext = path.extname(item);
          if (extensions.includes(ext)) {
            results.push(fullPath);
          }
        }
      }
    }

    walk(dir);
    return results;
  }

  // 处理单个文件
  async processFile(filePath, replacements, isPreview) {
    let content = fs.readFileSync(filePath, 'utf-8');
    let modified = false;
    let newContent = content;

    for (const { from, to, regex } of replacements) {
      if (regex) {
        // 正则替换
        if (regex.test(newContent)) {
          newContent = newContent.replace(regex, to);
          modified = true;
        }
      } else {
        // 字符串替换
        if (newContent.includes(from)) {
          newContent = newContent.split(from).join(to);
          modified = true;
        }
      }
    }

    if (modified) {
      if (isPreview) {
        console.log(`📝 [预览] 将修改: ${filePath}`);
        this.stats.skipped++;
      } else {
        fs.writeFileSync(filePath, newContent, 'utf-8');
        console.log(`✓ 已修改: ${filePath}`);
        this.stats.modified++;
      }
    }
  }

  // 输出统计信息
  printStats() {
    console.log('\n=== 批量替换统计 ===');
    console.log(`扫描文件: ${this.stats.scanned}`);
    console.log(`修改文件: ${this.stats.modified}`);
    console.log(`预览跳过: ${this.stats.skipped}`);
    if (this.stats.errors.length > 0) {
      console.log(`\n错误列表:`);
      this.stats.errors.forEach(e => console.log(`  - ${e.file}: ${e.error}`));
    }
  }
}

// 使用示例
const replacer = new BatchReplacer();

// 定义替换规则
const replacements = [
  { from: '/api/v1/users', to: '/api/v2/users' },
  { from: '/api/v1/products', to: '/api/v2/products' },
  { regex: /\/api\/v1\/admin/g, to: '/api/v2/admin' },
];

// 先预览
console.log('=== 预览模式 ===');
replacer.replaceInFiles('./src', replacements, { preview: true })
  .then(stats => replacer.printStats());

// 确认后执行实际替换
// replacer.replaceInFiles('./src', replacements, { preview: false })
//   .then(stats => replacer.printStats());

